code = """import pandas as pd
import json
from datetime import datetime

# Load data (objects are already lists/dicts)
cases = locals()['var_function-call-13873770102037454678']
history = locals()['var_function-call-6827241923082319029']

# Date range: 2022-04-01 to 2023-03-31
start_date = datetime(2022, 4, 1)
end_date = datetime(2023, 3, 31, 23, 59, 59)

def parse_date(d_str):
    try:
        # 2022-05-15T14:00:00.000+0000
        return datetime.strptime(d_str[:19], "%Y-%m-%dT%H:%M:%S")
    except:
        return None

handled_agents = set()
transfer_counts = {}

# Process History
for h in history:
    d = parse_date(h['createddate'])
    if d and start_date <= d <= end_date:
        old_val = h['oldvalue__c']
        new_val = h['newvalue__c']
        
        # Clean IDs
        if old_val: old_val = old_val.strip().lstrip('#')
        if new_val: new_val = new_val.strip().lstrip('#')
        
        # old_val (sender)
        if old_val and old_val.lower() != 'none':
            handled_agents.add(old_val)
            transfer_counts[old_val] = transfer_counts.get(old_val, 0) + 1
            
        # new_val (receiver)
        if new_val and new_val.lower() != 'none':
            handled_agents.add(new_val)

# Process Cases
for c in cases:
    d = parse_date(c['createddate'])
    if d and start_date <= d <= end_date:
        owner = c['ownerid']
        if owner:
            owner = owner.strip().lstrip('#')
            if owner.lower() != 'none':
                handled_agents.add(owner)

results = []
for agent in handled_agents:
    count = transfer_counts.get(agent, 0)
    results.append({'agent': agent, 'transfers': count})

# Sort by transfers (asc), then agent (asc)
results.sort(key=lambda x: (x['transfers'], x['agent']))

# Print first result
final_agent = results[0]['agent'] if results else None
print('__RESULT__:')
print(json.dumps(final_agent))"""

